import React from 'react';
export default function Home(){
  return (
    <div style={{padding:20}}>
      <h1>MindConnect — Student Support</h1>
      <p>Gamified mental-health platform for students. <a href="/login">Start anonymously</a>.</p>
      <div style={{marginTop:20}}>
        <img src="https://via.placeholder.com/600x200?text=MindConnect+Banner" alt="banner"/>
      </div>
    </div>
  );
}
